import java.util.*;

public class Solution {
    public static long solve(long[][] edges, boolean[] online, long k) {
        int n = online.length;
        List<List<Edge>> graph = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            graph.add(new ArrayList<>());
        }
        for (long[] e : edges) {
            int u = (int) e[0];
            int v = (int) e[1];
            long cost = e[2];
            graph.get(u).add(new Edge(v, cost));
        }

        PriorityQueue<State> pq = new PriorityQueue<>((a, b) -> {
            if (a.min_edge != b.min_edge) {
                return Long.compare(b.min_edge, a.min_edge);
            }
            return Long.compare(a.total_cost, b.total_cost);
        });
        pq.add(new State(0, 0, Long.MAX_VALUE));

        long max_score = -1;

        while (!pq.isEmpty()) {
            State current = pq.poll();
            int u = current.node;
            long total_cost = current.total_cost;
            long min_edge = current.min_edge;

            if (u == n - 1) {
                if (total_cost <= k) {
                    max_score = Math.max(max_score, min_edge);
                }
                continue;
            }

            for (Edge e : graph.get(u)) {
                int v = e.to;
                long cost = e.cost;
                if (v != n - 1 && !online[v]) {
                    continue;
                }
                long new_total = total_cost + cost;
                if (new_total > k) {
                    continue;
                }
                long new_min = Math.min(min_edge, cost);
                pq.add(new State(v, new_total, new_min));
            }
        }

        return max_score;
    }

    static class Edge {
        int to;
        long cost;
        Edge(int to, long cost) {
            this.to = to;
            this.cost = cost;
        }
    }

    static class State {
        int node;
        long total_cost;
        long min_edge;
        State(int node, long total_cost, long min_edge) {
            this.node = node;
            this.total_cost = total_cost;
            this.min_edge = min_edge;
        }
    }
}
